/* ---- Competitor Ad Creatives ---- */
.creatives-section {
  background: var(--card-bg);
  border: 1px solid var(--card-border);
  border-radius: 10px;
  padding: 1.75rem;
  margin-bottom: 2.5rem;
}

.creatives-section .section-header {
  text-align: center;
  margin-bottom: 1.75rem;
}

.creatives-section .section-header h3 {
  font-size: 1.15rem;
  color: var(--text-primary);
  margin-bottom: 0.25rem;
}

.creatives-section .section-header p {
  font-size: 0.8rem;
  color: var(--text-secondary);
}

.competitor-creatives {
  margin-bottom: 2rem;
}

.competitor-creatives:last-child {
  margin-bottom: 0;
}

.competitor-creatives h4 {
  font-size: 0.9rem;
  font-weight: 600;
  margin-bottom: 0.75rem;
  padding-bottom: 0.4rem;
}

.competitor-creatives h4.accent-amber {
  color: var(--orange);
  border-bottom: 1px solid rgba(219, 109, 40, 0.25);
}

.competitor-creatives h4.accent-red {
  color: var(--red);
  border-bottom: 1px solid rgba(248, 81, 73, 0.25);
}

.creative-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(240px, 280px));
  gap: 1rem;
  margin-bottom: 1rem;
}

.creative-item {
  display: flex;
  flex-direction: column;
  align-items: center;
}

.creative-item img {
  max-width: 280px;
  width: 100%;
  border-radius: 8px;
  border: 1px solid var(--card-border);
}

.creative-item .creative-label {
  font-size: 0.75rem;
  color: var(--text-secondary);
  margin-top: 0.4rem;
  text-align: center;
}

.callout-green {
  background: rgba(63, 185, 80, 0.08);
  border: 1px solid rgba(63, 185, 80, 0.25);
  color: var(--green);
}

.callout-orange {
  background: rgba(219, 109, 40, 0.08);
  border: 1px solid rgba(219, 109, 40, 0.25);
  color: var(--orange);
}

@media (max-width: 960px) {
  .cards { grid-template-columns: 1fr; }
  .creative-grid { grid-template-columns: repeat(auto-fill, minmax(200px, 1fr)); }
}

